code.C:
#include <stdio.h>
int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    const double temp = 25.5;
    for (int i = 0; i < T; ++i) {
        printf("Celsius - %.1f\nKelvin - %.1f", temp, temp + 273.15);
        if (i != T - 1) printf("\n");
    }
    return 0;
}

