using namespace std;
int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T;
    if (!(cin >> T)) return 0;
    const double temp = 25.5;
    for (int i = 0; i < T; ++i) {
        cout << "Celsius - " << fixed << setprecision(1) << temp << "\n";
        cout << "Kelvin - " << fixed << setprecision(1) << temp + 273.15;
        if (i != T - 1) cout << '\n';
    }
    return 0;
}

code.Java:
import java.io.*;
public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        String line = br.readLine();
        if (line == null || line.isEmpty()) return;
        int T = Integer.parseInt(line.trim());
        double temp = 25.5;
        StringBuilder sb = new StringBuilder();
        for (int i = 0; i < T; ++i) {
            sb.append(String.format("Celsius - %.1f\nKelvin - %.1f", temp, temp + 273.15));
            if (i != T - 1) sb.append('\n');
        }
        System.out.print(sb.toString());
    }
}

